  /* vsim path: sim_control treats command < 256 as a raw exit code.
     Silently dropped (unassigned MMIO) on QEMU virt. */
  volatile uint32_t* command = (volatile uint32_t*) EXIT_COMMAND_ADDR;
  *command = (uint32_t)(exit_status & 0xFF);

  /* QEMU virt path: RISC-V semihosting SYS_EXIT_EXTENDED. Same ebreak triple as
     hybrid/test/semihost_exit.inc. Block lives in .bss, not at fixed 0x80001000. */
  static volatile uint64_t semihost_block[2];
  semihost_block[0] = 0x20026; /* ADP_Stopped_ApplicationExit */
  semihost_block[1] = (uint64_t)(uint32_t) exit_status;
  register long a0 __asm__("a0") = 0x20; /* SYS_EXIT_EXTENDED */
  register long a1 __asm__("a1") = (long)(uintptr_t) semihost_block;
  __asm__ __volatile__(
    ".option push\n"
    ".option norvc\n"
    "slli x0, x0, 0x1f\n"
    "ebreak\n"
    "srai x0, x0, 0x7\n"
    ".option pop\n"
    : : "r"(a0), "r"(a1) : "memory");

  __asm__ __volatile__("1: j 1b");
  __builtin_unreachable();
}

