/* Tier-1 C-level round-trip smoke test.
 *
 * Phase A (QEMU1): bring-up via crt0.S, hits csrwi 0x7C0, 0 -- plugin drains
 *   GPR/PC/CSR state and exits. No libgloss reachable.
 * Phase B (vsim):  printf via newlib stdio -> _write fd 1 -> per-byte poke to
 *   sim_control HTIF_PUTCHAR (0xE0080004); hits csrwi 0x7C0, 1 -- vsim drains
 *   and spawns QEMU2.
 * Phase C (QEMU2): main() returns 0 -> crt0 calls _exit(0) -> dual-path _exit
 *   silently writes 0xE0080000 (no-op on QEMU virt) then issues semihosting
 *   SYS_EXIT_EXTENDED, terminating QEMU2 with status 0.
 */

#include "runtime/rt_c_helpers.h"

int main(void)
{
  rt_phase_qemu1_drain();

  /* Unbuffered so each byte hits sim_control before the vsim drain marker;
   * stdout is otherwise block-buffered when not connected to a tty. */
  setvbuf(stdout, NULL, _IONBF, 0);

  printf("hello from vsim\n");

  rt_phase_vsim_drain();
  return 0;
}

